// // This module implements a 4-bit up counter with an active-high enable signal. The counter increments its value on each clock cycle when the enable signal is high. When the count reaches 16, it wraps around to 0. The counter also has a reset signal that sets the count back to 0 when asserted.
module down_counter(  
    input clk,  
    input reset,  
    input enable,  
    output reg [3:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            count <= 4'b1111;  
        end else if (!enable) begin  
            if (count == 4'b0000)  
                count <= 4'b1111;  
            else  
                count <= count - 1;  
        end  
    end  
endmodule
